import React from 'react';
import { MapPin, Star } from 'lucide-react';
import { Link } from 'react-router-dom';

const PropertyCard = ({ property }) => {
    return (
        <Link to={`/properties/${property.id}`} className="block group">
            <div className="relative overflow-hidden rounded-xl aspect-[4/3]">
                <img
                    src={property.images?.[0] || 'https://images.unsplash.com/photo-1566073771259-6a8506099945?ixlib=rb-4.0.3&auto=format&fit=crop&w=1170&q=80'}
                    alt={property.title}
                    className="object-cover w-full h-full transition-transform duration-300 group-hover:scale-110"
                />
                <div className="absolute top-3 right-3 bg-white/90 backdrop-blur-sm px-2 py-1 rounded-md flex items-center gap-1 text-sm font-medium shadow-sm">
                    <Star className="w-4 h-4 text-yellow-500 fill-yellow-500" />
                    <span>{property.rating || 'New'}</span>
                </div>
            </div>

            <div className="mt-3 space-y-1">
                <div className="flex justify-between items-start">
                    <h3 className="font-semibold text-lg text-gray-900 truncate pr-4">{property.title}</h3>
                </div>

                <div className="flex items-center gap-1 text-gray-500 text-sm">
                    <MapPin className="w-4 h-4" />
                    <span className="truncate">{property.location}</span>
                </div>

                <div className="flex items-baseline gap-1 mt-2">
                    <span className="font-semibold text-gray-900">₹{property.pricePerNight}</span>
                    <span className="text-gray-500">night</span>
                </div>
            </div>
        </Link>
    );
};

export default PropertyCard;
